const raw = $json.output ?? "";

const cleaned = String(raw)
  .replace(/```json/g, "")
  .replace(/```/g, "")
  .trim();

let audioOverview;

try {
  audioOverview = JSON.parse(cleaned);

  if (!Array.isArray(audioOverview.segments)) {
    throw new Error("Invalid audio overview format");
  }
} catch (error) {
  audioOverview = {
    title: "Demo Audio Overview",
    description: "A fallback Study Aura audio overview script.",
    estimatedDuration: "1 minute",
    segments: [
      {
        speaker: "Narrator",
        text: "Welcome to this Study Aura audio overview. Today, we are reviewing Marine Biology, the study of life in the ocean."
      },
      {
        speaker: "Narrator",
        text: "Key examples include dolphins, coral reefs, and marine ecosystems. These help us understand how ocean life survives and interacts."
      }
    ],
    recap: ["Marine biology studies ocean life", "Dolphins are marine mammals", "Coral reefs support biodiversity"]
  };
}

const segments = audioOverview.segments.map((segment) => ({
  speaker: String(segment.speaker || "Narrator"),
  text: String(segment.text || "Review this topic carefully.")
}));

return [
  {
    json: {
      audioOverview: {
        title: String(audioOverview.title || "Study Aura Audio Overview"),
        description: String(audioOverview.description || "Generated audio overview script."),
        estimatedDuration: String(audioOverview.estimatedDuration || "2 minutes"),
        segments,
        recap: Array.isArray(audioOverview.recap)
          ? audioOverview.recap.map((item) => String(item))
          : []
      },
      fallback: false
    }
  }
];

